body.script:

                        const root = document.getElementById("app");
                        const flowchart = JSON.parse(root.dataset.flowchart || "{}");

                        const NODE_W = flowchart.node_width || 260;
                        const NODE_H = flowchart.node_height || 96;
                        const nodes = flowchart.nodes || [];
                        const edges = flowchart.edges || [];
                        const worldSize = flowchart.world || { width: 1200, height: 900 };
                        const templateId = flowchart.template?.id;

                        const stage = document.getElementById("stage");
                        const world = document.getElementById("world");
                        const svg = document.getElementById("edges");
                        const pct = document.getElementById("pct");
                        const saveLayoutButton = document.getElementById("saveLayout");
                        const resetLayoutButton = document.getElementById("resetLayout");
                        const layoutStatus = document.getElementById("layoutStatus");

                        world.style.width = `${worldSize.width}px`;
                        world.style.height = `${worldSize.height}px`;
                        svg.setAttribute("width", String(worldSize.width));
                        svg.setAttribute("height", String(worldSize.height));

                        if (!nodes.length) {
                            const empty = document.createElement("div");
                            empty.className = "empty-state";
                            empty.innerHTML = `
                                <h2>No tasks to draw</h2>
                                <p>Add procedure template tasks and connect them to preview the flowchart here.</p>
                            `;
                            root.appendChild(empty);
                        }

                        const byId = new Map(nodes.map((node) => [node.id, node]));
                        const taskNodes = nodes.filter((node) => node.type !== "subprocedure");
                        const subprocedureNodes = nodes.filter((node) => node.type === "subprocedure");

                        function taskBoundaryX() {
                            return taskNodes.length
                                ? Math.max(...taskNodes.map((node) => node.x + nodeWidth(node)))
                                : 0;
                        }

                        function subprocedureBoundaryX() {
                            return subprocedureNodes.length
                                ? Math.min(...subprocedureNodes.map((node) => node.x))
                                : worldSize.width;
                        }

                        function buildSourceTrackMap() {
                            const sources = Array.from(new Set(
                                edges
                                    .filter((edge) => edge.kind === "subprocedure")
                                    .map((edge) => edge.from)
                            )).sort((leftId, rightId) => {
                                const leftNode = byId.get(leftId);
                                const rightNode = byId.get(rightId);
                                if ((leftNode?.y || 0) !== (rightNode?.y || 0)) {
                                    return (leftNode?.y || 0) - (rightNode?.y || 0);
                                }
                                return (leftNode?.x || 0) - (rightNode?.x || 0);
                            });

                            const trackMap = new Map();
                            if (!sources.length) return trackMap;

                            const boundaryX = taskBoundaryX();
                            const subBoundaryX = subprocedureBoundaryX();
                            const topLaneBottom = taskNodes.length
                                ? Math.max(28, Math.min(...taskNodes.map((node) => node.y)) - 28)
                                : 28;
                            const laneSpacingY = 18;
                            const topLaneTop = Math.max(12, topLaneBottom - ((sources.length - 1) * laneSpacingY));
                            const trackStartX = boundaryX + 48;
                            const trackEndX = Math.max(trackStartX, subBoundaryX - 68);
                            const trackSpanX = trackEndX - trackStartX;

                            sources.forEach((sourceId, index) => {
                                const sourceNode = byId.get(sourceId);
                                const exitBase = sourceNode
                                    ? sourceNode.x + nodeWidth(sourceNode) + 18
                                    : boundaryX + 30;
                                const ratio = sources.length === 1
                                    ? 0.5
                                    : index / (sources.length - 1);
                                trackMap.set(sourceId, {
                                    exitX: exitBase + (index * 12),
                                    trackY: topLaneTop + (index * laneSpacingY),
                                    trackX: trackStartX + (trackSpanX * ratio),
                                });
                            });

                            return trackMap;
                        }

                        function escapeHtml(value) {
                            return String(value).replace(/[&<>"']/g, (char) => ({
                                "&": "&amp;",
                                "<": "&lt;",
                                ">": "&gt;",
                                '"': "&quot;",
                                "'": "&#39;",
                            }[char]));
                        }

                        function nodeWidth(node) {
                            return node.width || NODE_W;
                        }

                        function nodeHeight(node) {
                            return node.height || NODE_H;
                        }

                        function point(node, side) {
                            const width = nodeWidth(node);
                            const height = nodeHeight(node);
                            if (side === "top") return { x: node.x + (width / 2), y: node.y };
                            if (side === "bottom") return { x: node.x + (width / 2), y: node.y + height };
                            if (side === "left") return { x: node.x, y: node.y + (height / 2) };
                            return { x: node.x + width, y: node.y + (height / 2) };
                        }

                        function renderNodes() {
                            const box = document.getElementById("nodes");
                            box.innerHTML = "";

                            for (const node of nodes) {
                                const element = document.createElement("div");
                                const classes = `node ${node.type || "task"}`;
                                const badges = (node.badges || []).map((badge) => (
                                    `<span class="badge">${escapeHtml(badge)}</span>`
                                )).join("");

                                element.className = classes;
                                element.dataset.nodeId = String(node.id);
                                element.style.left = `${node.x}px`;
                                element.style.top = `${node.y}px`;
                                element.style.width = `${nodeWidth(node)}px`;
                                element.style.minHeight = `${nodeHeight(node)}px`;

                                element.innerHTML = `
                                    <div class="node-body">
                                        <div class="tag">${escapeHtml(node.tag || "TASK")}</div>
                                        <div class="title">${escapeHtml(node.label)}</div>
                                        ${badges ? `<div class="badges">${badges}</div>` : ""}
                                    </div>
                                `;

                                if (node.type !== "subprocedure") {
                                    element.addEventListener("mousedown", (event) => {
                                        beginNodeDrag(event, node, element);
                                    });
                                }

                                box.appendChild(element);
                            }
                        }

	                        function drawPath(pathData, edgeKind, isChoice) {
	                            if (isChoice && edgeKind !== "subprocedure") {
	                                const buffer = document.createElementNS("http://www.w3.org/2000/svg", "path");
	                                buffer.setAttribute("d", pathData);
	                                buffer.setAttribute("class", "edge-buffer");
	                                svg.appendChild(buffer);
	                            }

	                            const path = document.createElementNS("http://www.w3.org/2000/svg", "path");
	                            path.setAttribute("d", pathData);
	                            let edgeClass = "edge";
                            let marker = "url(#arrow)";
                            if (edgeKind === "subprocedure") {
                                edgeClass += " subprocedure";
                                marker = "url(#arrowSubprocedure)";
                            } else if (isChoice) {
                                edgeClass += " choice";
                                marker = "url(#arrowChoice)";
                            }
                            path.setAttribute("class", edgeClass);
                            path.setAttribute("marker-end", marker);
                            svg.appendChild(path);
                        }

                        function drawLabel(text, x, y, edgeKind) {
                            const label = document.createElementNS("http://www.w3.org/2000/svg", "text");
                            label.setAttribute("x", x);
                            label.setAttribute("y", y);
                            label.setAttribute("text-anchor", "middle");
                            label.setAttribute("dominant-baseline", "middle");
                            label.setAttribute("class", edgeKind === "subprocedure" ? "label subprocedure" : "label");
                            label.textContent = text;

                            svg.appendChild(label);

                            const box = label.getBBox();
                            const background = document.createElementNS("http://www.w3.org/2000/svg", "rect");
                            background.setAttribute("x", box.x - 8);
                            background.setAttribute("y", box.y - 4);
                            background.setAttribute("width", box.width + 16);
                            background.setAttribute("height", box.height + 8);
                            background.setAttribute("rx", 4);
                            background.setAttribute("ry", 4);
                            background.setAttribute("class", "label-bg");

                            svg.insertBefore(background, label);
                        }

                        function buildEdgePath(edge, sourceTrackMap) {
                            const source = byId.get(edge.from);
                            const target = byId.get(edge.to);
                            if (!source || !target) return null;

                            const start = edge.kind === "subprocedure" ? point(source, "right") : point(source, "bottom");
                            const end = edge.kind === "subprocedure" ? point(target, "left") : point(target, "top");
                            const midY = start.y + Math.max((end.y - start.y) / 2, 40);

	                            if (edge.kind === "subprocedure") {
	                                const track = sourceTrackMap.get(edge.from) || {
	                                    exitX: start.x + 20,
                                    trackY: Math.max(18, start.y - 36),
                                    trackX: taskBoundaryX() + 60,
                                };
                                return {
                                    path: `M ${start.x} ${start.y} L ${track.exitX} ${start.y} L ${track.exitX} ${track.trackY} L ${track.trackX} ${track.trackY} L ${track.trackX} ${end.y} L ${end.x - 5} ${end.y}`,
                                    labelPoint: {
                                        x: track.trackX,
                                        y: track.trackY - 12,
                                    },
	                                };
	                            }

	                            if (edge.choice) {
	                                const targetAboveSource = target.y < source.y;
	                                const sameRow = Math.abs(source.y - target.y) < 8;
	                                const targetOffset = Math.max(30, Math.min(58, (Math.abs(end.y - start.y) || 120) / 3));
	                                const trackY = sameRow
	                                    ? Math.max(18, source.y - targetOffset)
	                                    : targetAboveSource
	                                        ? target.y + nodeHeight(target) + targetOffset
	                                        : Math.max(start.y + 24, target.y - targetOffset);
	                                const stemOffset = Math.max(18, Math.min(46, Math.abs(end.x - start.x) / 4));
	                                const startX = start.x + (end.x >= start.x ? stemOffset : -stemOffset);
	                                const endX = end.x + (end.x >= start.x ? -stemOffset : stemOffset);

	                                return {
	                                    path: `M ${start.x} ${start.y} L ${startX} ${start.y} L ${startX} ${trackY} L ${end.x} ${trackY} L ${end.x} ${end.y - 5}`,
	                                    labelPoint: {
	                                        x: (startX + endX) / 2,
	                                        y: trackY - 14,
	                                    },
	                                };
	                            }

	                            if (Math.abs(source.y - target.y) < 8) {
                                const sourceSide = source.x <= target.x ? "right" : "left";
	                                const targetSide = source.x <= target.x ? "left" : "right";
	                                const sameRowStart = point(source, sourceSide);
	                                const sameRowEnd = point(target, targetSide);
	                                const midX = sameRowStart.x + ((sameRowEnd.x - sameRowStart.x) / 2);
	                                const laneY = Math.max(18, Math.min(source.y, target.y) - 32);

	                                return {
	                                    path: `M ${sameRowStart.x} ${sameRowStart.y} L ${sameRowStart.x} ${laneY} L ${midX} ${laneY} L ${sameRowEnd.x} ${laneY} L ${sameRowEnd.x} ${sameRowEnd.y}`,
	                                    labelPoint: {
	                                        x: midX,
	                                        y: laneY - 14,
	                                    },
	                                };
	                            }

                            return {
                                path: `M ${start.x} ${start.y} L ${start.x} ${midY} L ${end.x} ${midY} L ${end.x} ${end.y - 5}`,
                                labelPoint: {
                                    x: (start.x + end.x) / 2,
                                    y: midY - 18,
                                },
                            };
                        }

                        function renderEdges() {
                            svg.innerHTML = `
                                <defs>
                                    <marker id="arrow" viewBox="0 0 10 10" refX="9" refY="5" markerWidth="7" markerHeight="7" orient="auto">
                                        <path d="M0,0 L10,5 L0,10 Z" class="arrow"></path>
                                    </marker>
                                    <marker id="arrowChoice" viewBox="0 0 10 10" refX="9" refY="5" markerWidth="7" markerHeight="7" orient="auto">
                                        <path d="M0,0 L10,5 L0,10 Z" class="arrow choice"></path>
                                    </marker>
                                    <marker id="arrowSubprocedure" viewBox="0 0 10 10" refX="9" refY="5" markerWidth="7" markerHeight="7" orient="auto">
                                        <path d="M0,0 L10,5 L0,10 Z" class="arrow subprocedure"></path>
                                    </marker>
                                </defs>
                            `;

	                            const orderedEdges = [
	                                ...edges.filter((edge) => !edge.choice && edge.kind !== "subprocedure"),
	                                ...edges.filter((edge) => edge.kind === "subprocedure"),
	                                ...edges.filter((edge) => edge.choice && edge.kind !== "subprocedure"),
	                            ];
                            const sourceTrackMap = buildSourceTrackMap();

	                            for (const edge of orderedEdges) {
	                                const edgeData = buildEdgePath(edge, sourceTrackMap);
	                                if (!edgeData) continue;

                                drawPath(edgeData.path, edge.kind, Boolean(edge.choice));
                                if (edge.label) {
                                    drawLabel(edge.label, edgeData.labelPoint.x, edgeData.labelPoint.y, edge.kind);
                                }
                            }
                        }

                        let scale = 0.85;
                        let tx = 0;
                        let ty = 0;
                        let dragging = false;
                        let nodeDragging = null;
                        let layoutDirty = false;
                        let lastX = 0;
                        let lastY = 0;

                        function applyTransform() {
                            world.style.transform = `translate(${tx}px, ${ty}px) scale(${scale})`;
                            pct.textContent = `${Math.round(scale * 100)}%`;
                        }

                        function setLayoutStatus(text) {
                            layoutStatus.textContent = text;
                        }

                        function markLayoutDirty() {
                            if (layoutDirty) return;
                            layoutDirty = true;
                            saveLayoutButton.disabled = false;
                            setLayoutStatus("Unsaved");
                        }

                        function updateWorldBounds() {
                            if (!nodes.length) return;

                            const padding = 120;
                            const maxX = Math.max(...nodes.map((node) => node.x + nodeWidth(node))) + padding;
                            const maxY = Math.max(...nodes.map((node) => node.y + nodeHeight(node))) + padding;
                            worldSize.width = Math.max(worldSize.width, maxX, 600);
                            worldSize.height = Math.max(worldSize.height, maxY, 420);
                            world.style.width = `${worldSize.width}px`;
                            world.style.height = `${worldSize.height}px`;
                            svg.setAttribute("width", String(worldSize.width));
                            svg.setAttribute("height", String(worldSize.height));
                        }

                        function beginNodeDrag(event, node, element) {
                            event.preventDefault();
                            event.stopPropagation();

                            nodeDragging = {
                                node,
                                element,
                                startX: event.clientX,
                                startY: event.clientY,
                                originX: node.x,
                                originY: node.y,
                            };
                            element.classList.add("dragging-node");
                            stage.classList.add("dragging");
                        }

                        function moveNodeDrag(event) {
                            if (!nodeDragging) return false;

                            const nextX = nodeDragging.originX + ((event.clientX - nodeDragging.startX) / scale);
                            const nextY = nodeDragging.originY + ((event.clientY - nodeDragging.startY) / scale);
                            nodeDragging.node.x = Math.max(Math.round(nextX), 0);
                            nodeDragging.node.y = Math.max(Math.round(nextY), 0);
                            nodeDragging.element.style.left = `${nodeDragging.node.x}px`;
                            nodeDragging.element.style.top = `${nodeDragging.node.y}px`;
                            updateWorldBounds();
                            renderEdges();
                            markLayoutDirty();
                            return true;
                        }

                        function endNodeDrag() {
                            if (!nodeDragging) return false;

                            nodeDragging.element.classList.remove("dragging-node");
                            nodeDragging = null;
                            stage.classList.remove("dragging");
                            return true;
                        }

                        async function postLayout(url, payload) {
                            const response = await fetch(url, {
                                method: "POST",
                                credentials: "same-origin",
                                headers: {
                                    "Content-Type": "application/json",
                                },
                                body: JSON.stringify(payload || {}),
                            });

                            if (!response.ok) {
                                throw new Error(`Request failed: ${response.status}`);
                            }

                            const data = await response.json();
                            if (data.status !== "success") {
                                throw new Error(data.message || "Request failed");
                            }
                            return data;
                        }

                        async function saveLayout() {
                            if (!templateId || !layoutDirty) return;

                            saveLayoutButton.disabled = true;
                            setLayoutStatus("Saving");
                            try {
                                await postLayout(`/ss_workflow/procedures/template/${templateId}/flowchart/layout`, {
                                    positions: taskNodes.map((node) => ({
                                        id: node.id,
                                        x: node.x,
                                        y: node.y,
                                    })),
                                });
                                layoutDirty = false;
                                setLayoutStatus("Saved");
                            } catch (error) {
                                saveLayoutButton.disabled = false;
                                setLayoutStatus("Failed");
                            }
                        }

                        async function resetLayout() {
                            if (!templateId) return;

                            saveLayoutButton.disabled = true;
                            resetLayoutButton.disabled = true;
                            setLayoutStatus("Resetting");
                            try {
                                await postLayout(`/ss_workflow/procedures/template/${templateId}/flowchart/layout/reset`, {});
                                window.location.reload();
                            } catch (error) {
                                resetLayoutButton.disabled = false;
                                saveLayoutButton.disabled = !layoutDirty;
                                setLayoutStatus("Failed");
                            }
                        }

                        function fitView() {
                            scale = Math.min(
                                stage.clientWidth / worldSize.width,
                                stage.clientHeight / worldSize.height,
                                1
                            );

                            tx = -(worldSize.width * scale) / 2;
                            ty = -(worldSize.height * scale) / 2;
                            applyTransform();
                        }

                        function zoomAt(px, py, factor) {
                            const nextScale = Math.max(0.25, Math.min(2.5, scale * factor));
                            const relative = nextScale / scale;
                            const centerX = px - (stage.clientWidth / 2);
                            const centerY = py - (stage.clientHeight / 2);

                            tx = centerX - ((centerX - tx) * relative);
                            ty = centerY - ((centerY - ty) * relative);
                            scale = nextScale;
                            applyTransform();
                        }

                        document.getElementById("fit").addEventListener("click", fitView);
                        saveLayoutButton.addEventListener("click", saveLayout);
                        resetLayoutButton.addEventListener("click", resetLayout);
                        document.getElementById("zoomIn").addEventListener("click", () => {
                            zoomAt(stage.clientWidth / 2, stage.clientHeight / 2, 1.2);
                        });
                        document.getElementById("zoomOut").addEventListener("click", () => {
                            zoomAt(stage.clientWidth / 2, stage.clientHeight / 2, 1 / 1.2);
                        });

                        stage.addEventListener("mousedown", (event) => {
                            dragging = true;
                            lastX = event.clientX;
                            lastY = event.clientY;
                            stage.classList.add("dragging");
                        });

                        window.addEventListener("mousemove", (event) => {
                            if (moveNodeDrag(event)) return;
                            if (!dragging) return;

                            tx += event.clientX - lastX;
                            ty += event.clientY - lastY;
                            lastX = event.clientX;
                            lastY = event.clientY;
                            applyTransform();
                        });

                        window.addEventListener("mouseup", () => {
                            if (endNodeDrag()) return;
                            dragging = false;
                            stage.classList.remove("dragging");
                        });

                        stage.addEventListener("wheel", (event) => {
                            event.preventDefault();
                            const rect = stage.getBoundingClientRect();
                            zoomAt(
                                event.clientX - rect.left,
                                event.clientY - rect.top,
                                event.deltaY < 0 ? 1.1 : (1 / 1.1)
                            );
                        }, { passive: false });

                        window.addEventListener("resize", fitView);

                        renderNodes();
                        renderEdges();
                        fitView();
